import _HTTPClient from "./HTTPClient";
import _WSClient from "./WSClient";
import _RegistryClient from "./RegistryClient";


export class HTTPClient extends _HTTPClient {
    constructor(host:string, port:number) {
        super(host, port);
    }
}

export class WSClient extends _WSClient {
    constructor(host:string) {
        super(host);
    }
}

export class RegistryClient extends _RegistryClient {
    constructor(host:string, port:number) {
        super(host, port);
    }

    public static get instance():RegistryClient {
        return _RegistryClient.instance;
    }
}

/**
 * Registration Record
 * @class RegistrationRecord
 */
export interface RegistrationRecord {
    /**
     * Name
     * @name RegistrationRecord#name
     * @type {String}
     */
    name:string;

    /**
     * Host
     * @name RegistrationRecord#host
     * @type {String}
     */
    host:string;

    /**
     * Port
     * @name RegistrationRecord#port
     * @type {Number}
     */
    port:number;

    /**
     * Path
     * @name RegistrationRecord#path
     * @type {String}
     */
    path:string;

    /**
     * TTL
     * @name RegistrationRecord#ttl
     * @type {Number}
     */
    ttl?:number;
    
    /**
     * TLS
     * @name RegistrationRecord#tls
     * @type {String}
     */
    tls?:string;
}

export default {};